class Node:
    def __init__(self, char):
        self.char = char
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.char:
        root.left = insert(root.left, char)
    elif char > root.char:
        root.right = insert(root.right, char)
    return root

def process_recursive(seq, index, root):
    if index >= len(seq):
        return root
    current_char = seq[index].lower()
    root = insert(root, current_char)
    return process_recursive(seq, index + 1, root)

